alice_messages = read_inbox("Alice")

bob_message = None
for msg in alice_messages:
    if msg.sender == "Bob":
        bob_message = msg

if bob_message is None:
    raise ValueError("No message from Bob found in Alice's inbox")

class NewColleagueInfo(BaseModel):
    name: str
    email: str
    channels: list[str]

colleague_info = query_ai_assistant(
    "Extract the new colleague's name (as a Slack username starting with a capital letter), "
    "her email address, and the list of Slack channels she should be added to, from the following message: "
    f"Sender: {bob_message.sender}, Recipient: {bob_message.recipient}, Body: {bob_message.body}",
    NewColleagueInfo
)

invite_user_to_slack(colleague_info.name, colleague_info.email)

available_channels = get_channels()

for channel in colleague_info.channels:
    matched_channel = None
    for c in available_channels:
        if c.lower() == channel.lower():
            matched_channel = c
    if matched_channel is not None:
        add_user_to_channel(colleague_info.name, matched_channel)
    else:
        add_user_to_channel(colleague_info.name, channel)

print(f"Invited {colleague_info.name} ({colleague_info.email}) to Slack and added to channels: {colleague_info.channels}")
